import { Printer, Download, Share2 } from 'lucide-react';

const App: React.FC = () => {
  const handlePrint = useCallback(() => {
    window.print();
  }, []);

  const handleShare = useCallback(() => {
    if (navigator.share) {
      navigator.share({
        title: 'Alex Diakov Resume',
        url: window.location.href,
      }).catch(console.error);
    } else {
      alert('Sharing is not supported on this device/browser.');
    }
  }, []);

  return (
    <div className="min-h-screen bg-slate-900 pb-12 print:bg-white print:pb-0">
      {/* Navigation / Toolbar - Hidden on Print */}
      <nav className="sticky top-0 z-50 bg-slate-800/95 backdrop-blur border-b border-slate-700 shadow-lg px-4 py-3 print:hidden mb-8">
        <div className="max-w-6xl mx-auto flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-2">
             <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-lg shadow-inner">
               A
             </div>
             <span className="text-white font-semibold tracking-wide">Alex Diakov <span className="text-slate-400 font-normal">| Portfolio & Resume</span></span>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-md font-medium text-sm transition-all shadow-md hover:shadow-blue-500/20 active:scale-95"
            >
              <Printer className="w-4 h-4" />
              <span>Print / Save PDF</span>
            </button>
            <button 
               onClick={handleShare}
               className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-slate-200 px-4 py-2 rounded-md font-medium text-sm transition-all active:scale-95"
            >
              <Share2 className="w-4 h-4" />
              <span className="hidden sm:inline">Share</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Main Container */}
      <main className="flex justify-center px-4 md:px-8 print:px-0 print:block">
