          {/* Resume Component */}
          <ResumePaper />

          <footer className="mt-12 text-center text-slate-500 text-xs print:hidden">
             <p>&copy; {new Date().getFullYear()} Alex Diakov. Designed with React & Tailwind CSS.</p>
          </footer>
        </div>
      </main>
    </div>
  );
};

