// Helper to bold specific patterns (numbers + %, currency)
const highlightText = (text: string) => {
  // Matches: 30%, 3-5x, $1M+, 20%
  const regex = /(\d+(?:[.,]\d+)?(?:%|x)|\$[0-9.]+[MK]?\+?)/g;
