import React, { useCallback, useEffect, useState } from 'react';
import { ResumePaper } from './components/ResumePaper';
import { Printer, Share2, Download, Loader2 } from 'lucide-react';

// Declare html2pdf on window
declare global {
  interface Window {
    html2pdf: any;
  }
}

const App: React.FC = () => {
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    // Set proper title for PDF export
    document.title = "Senior_Product_Designer_Alex_Diakov_2025";
  }, []);

  const handlePrint = useCallback(() => {
    window.print();
  }, []);

  const handleDownloadPdf = useCallback(async () => {
    if (typeof window.html2pdf === 'undefined') {
      alert('PDF generation library not loaded yet. Please wait a moment.');
      return;
    }

    setIsGenerating(true);

    const element = document.getElementById('resume-content');
    if (!element) return;

    // Clone the element to manipulate styles for clean PDF generation without modifying the UI
    const clone = element.cloneNode(true) as HTMLElement;

    // Create a container off-screen to hold the clone
    const container = document.createElement('div');
    container.style.position = 'absolute';
    container.style.top = '-9999px';
    container.style.left = '0';
    // Fix width to ensure 'md' breakpoints (desktop layout) are respected during canvas render
    container.style.width = '210mm'; 
    container.appendChild(clone);
    document.body.appendChild(container);

    // Styling fixes for the clone to ensure perfect PDF rendering
    clone.style.gap = '0';
    clone.querySelectorAll('.shadow-2xl').forEach((el: any) => {
      el.classList.remove('shadow-2xl');
      el.classList.add('shadow-none');
    });

    // --- LOGIC VERIFICATION & STRICT SIZING ---
    // Ensure the individual pages in the clone don't clip content or spill over
    const pages = clone.querySelectorAll('[id^="resume-page-"]');
    pages.forEach((page: any, index) => {
      // 1. Force strict dimensions
      page.style.width = '210mm';
      page.style.margin = '0';

      // 2. Set strict height to 296mm (1mm buffer less than A4) to prevent ANY browser rounding errors
      // triggering a new page.
      page.style.height = '296mm'; 
      page.style.maxHeight = '296mm';

      // 3. Hide overflow. This ensures that if content is 297.1mm, the 0.1mm doesn't create a blank page.
      // (We reduced gap in ResumePaper to ensure content fits naturally)
      page.style.overflow = 'hidden'; 

      // 4. Force page break logic manually
      if (index < pages.length - 1) {
        page.style.pageBreakAfter = 'always';
        page.style.marginBottom = '0';
      } else {
        page.style.pageBreakAfter = 'avoid';
      }

