const highlightText = (text: string) => {
  const regex = /(\d+(?:[.,]\d+)?(?:%|x)|\$[0-9.]+[MK]?\+?)/g;
  const parts = text.split(regex);
  return parts.map((part, i) => 
    regex.test(part) ? <strong key={i} className="font-bold text-resume-primary">{part}</strong> : part
  );
};

