import React, { useCallback, useEffect, useState, useRef } from 'react';
import { ResumePaper } from './components/ResumePaper';
import { Printer, Share2, Download, Loader2, Edit, Save, Upload, FileJson } from 'lucide-react';
import { INITIAL_RESUME_DATA } from './constants';
import { ResumeData } from './types';

// Declare html2pdf on window
declare global {
  interface Window {
    html2pdf: any;
  }
}

const App: React.FC = () => {
  const [isGenerating, setIsGenerating] = useState(false);
  const [resumeData, setResumeData] = useState<ResumeData>(INITIAL_RESUME_DATA);
  const [isEditing, setIsEditing] = useState(false);
  const [jsonInput, setJsonInput] = useState('');
  const [jsonError, setJsonError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load from LocalStorage on mount
  useEffect(() => {
    document.title = "Senior_Product_Designer_Alex_Diakov_2025";
    const savedData = localStorage.getItem('resume_data_v1');
    if (savedData) {
      try {
        setResumeData(JSON.parse(savedData));
      } catch (e) {
        console.error("Failed to load saved data", e);
      }
    }
  }, []);

  // Save to LocalStorage whenever data changes
  useEffect(() => {
    localStorage.setItem('resume_data_v1', JSON.stringify(resumeData));
  }, [resumeData]);

  // Editing Handlers
  const handleEditClick = () => {
    setJsonInput(JSON.stringify(resumeData, null, 2));
    setJsonError(null);
    setIsEditing(true);
  };

  const handleSaveJson = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      setResumeData(parsed);
      setIsEditing(false);
    } catch (e: any) {
      setJsonError("Invalid JSON: " + e.message);
    }
  };

  const handleExportJson = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(resumeData, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "resume_data.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result as string;
        const parsed = JSON.parse(text);
        setResumeData(parsed);
        // Also update the editor input if it's open
        if (isEditing) {
          setJsonInput(JSON.stringify(parsed, null, 2));
        }
      } catch (err) {
        alert("Failed to parse JSON file.");
      }
    };
    reader.readAsText(file);
    // Reset input
    event.target.value = '';
  };

  const handlePrint = useCallback(() => {
    window.print();
  }, []);

  const handleDownloadPdf = useCallback(async () => {
    if (typeof window.html2pdf === 'undefined') {
      alert('PDF generation library not loaded yet. Please wait a moment.');
      return;
    }

    setIsGenerating(true);

    const element = document.getElementById('resume-content');
    if (!element) return;

    // 1. Clone the element
    const clone = element.cloneNode(true) as HTMLElement;

    // 2. Prepare container
    const container = document.createElement('div');
    container.style.position = 'absolute';
    container.style.top = '-10000px';
    container.style.left = '0';
    container.style.width = '210mm'; 
    container.appendChild(clone);
    document.body.appendChild(container);

    // 3. Basic CSS Cleanups
    clone.style.gap = '0';
    clone.querySelectorAll('.shadow-2xl').forEach((el: any) => {
      el.classList.remove('shadow-2xl');
      el.classList.add('shadow-none');
    });

    // 4. WHITESPACE COMPRESSION LOGIC
    const reduceSpacing = (selector: string, oldClass: string, newClass: string) => {
      clone.querySelectorAll(selector).forEach((el: any) => {
        el.classList.replace(oldClass, newClass);
      });
    };

    reduceSpacing('.experience-block', 'mb-8', 'mb-6');
    reduceSpacing('.resume-header', 'pb-8', 'pb-5');
    reduceSpacing('.summary-section', 'mb-10', 'mb-6');
    reduceSpacing('.main-grid', 'gap-10', 'gap-6');
    reduceSpacing('.main-grid', 'gap-6', 'gap-4');
    reduceSpacing('.project-block', 'mb-6', 'mb-5');

    // 5. FIT-TO-PAGE SCALING LOGIC
    const A4_HEIGHT_PX = 1123; // Approx A4 height at 96 DPI
    const SAFETY_MARGIN = 20;
    const MAX_CONTENT_HEIGHT = A4_HEIGHT_PX - SAFETY_MARGIN;

    const pages = clone.querySelectorAll('[id^="resume-page-"]');
    pages.forEach((page: any, index) => {
      // Set container constraints
      page.style.width = '210mm';
      page.style.height = '296mm'; // Strict height
      page.style.margin = '0';
      // CRITICAL FIX: Ensure overflow is visible initially so we can measure true height
      page.style.overflow = 'visible'; 
      page.style.position = 'relative';

      // Find the inner content wrapper
      const content = page.querySelector(`#page-content-${index + 1}`) as HTMLElement;

      if (content) {
        // Reset height to auto to ensure we capture full content size even if CSS clipped it
        content.style.height = 'auto';

        // Measure natural height of content
        const naturalHeight = content.scrollHeight;

        console.log(`Page ${index + 1}: Natural Height = ${naturalHeight}px / Available = ${MAX_CONTENT_HEIGHT}px`);

        if (naturalHeight > MAX_CONTENT_HEIGHT) {
           const scaleFactor = MAX_CONTENT_HEIGHT / naturalHeight;
           console.warn(`Page ${index + 1} overflow detected. Scaling content by factor: ${scaleFactor.toFixed(4)}`);

           // Apply Scale to Fit
           content.style.transform = `scale(${scaleFactor})`;
           content.style.transformOrigin = 'top center';
           content.style.width = `calc(100% * ${1/scaleFactor})`; 
        }
      }

      // Now lock the overflow
      page.style.overflow = 'hidden';

      // Handle Page Breaks
      if (index < pages.length - 1) {
        page.style.pageBreakAfter = 'always';
        page.style.marginBottom = '0';
      } else {
        page.style.pageBreakAfter = 'avoid';
      }

      page.classList.remove('min-h-[297mm]');
    });

    // 6. Config options
    const opt = {
      margin: 0,
      filename: 'Senior_Product_Designer_Alex_Diakov_2025.pdf',
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { 
        scale: 2, 
        useCORS: true, 
        logging: true,
        scrollY: 0,
        windowWidth: 1200, 
        letterRendering: true, 
      },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: 'css' } 
    };

    try {
      await new Promise(resolve => setTimeout(resolve, 500));
      await window.html2pdf().set(opt).from(clone).save();
    } catch (err) {
      console.error(err);
      alert('Failed to generate PDF. Please try the "Print / Save PDF" option.');
    } finally {
      document.body.removeChild(container);
      setIsGenerating(false);
    }
  }, []);

  const handleShare = useCallback(() => {
    if (navigator.share) {
      navigator.share({
        title: 'Alex Diakov Resume',
        url: window.location.href,
      }).catch(console.error);
    } else {
      alert('Sharing is not supported on this device/browser.');
    }
  }, []);

  return (
    <div className="min-h-screen bg-slate-900 pb-12 print:bg-white print:pb-0 font-sans">
      {/* Navigation / Toolbar - Hidden on Print */}
      <nav className="sticky top-0 z-50 bg-slate-800/95 backdrop-blur border-b border-slate-700 shadow-lg px-4 py-3 print:hidden mb-8">
        <div className="max-w-[210mm] mx-auto flex flex-col xl:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-2">
             <div className="w-8 h-8 bg-resume-accent rounded-lg flex items-center justify-center text-white font-bold text-lg shadow-inner">
               A
             </div>
             <span className="text-white font-semibold tracking-wide hidden sm:inline">Alex Diakov <span className="text-slate-400 font-normal">| Portfolio</span></span>
          </div>

          <div className="flex flex-wrap items-center justify-center gap-3">
             <button 
              onClick={handleEditClick}
              className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-3 py-2 rounded-md font-medium text-xs transition-all border border-slate-600"
            >
              <Edit className="w-4 h-4" />
              <span>Edit Data</span>
            </button>
            <button 
               onClick={handleImportClick}
               className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-3 py-2 rounded-md font-medium text-xs transition-all border border-slate-600"
            >
              <Upload className="w-4 h-4" />
              <span>Load</span>
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              className="hidden" 
              accept=".json"
            />

            <div className="h-6 w-px bg-slate-600 mx-1 hidden sm:block"></div>

            <button 
              onClick={handleDownloadPdf}
              disabled={isGenerating}
              className="flex items-center gap-2 bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded-md font-medium text-sm transition-all shadow-md active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isGenerating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
              <span>Download PDF</span>
            </button>
            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 bg-resume-accent hover:bg-blue-600 text-white px-4 py-2 rounded-md font-medium text-sm transition-all shadow-md active:scale-95"
            >
              <Printer className="w-4 h-4" />
              <span>Print</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Editor Modal */}
      {isEditing && (
        <div className="fixed inset-0 z-[60] bg-black/80 flex items-center justify-center p-4">
          <div className="bg-slate-800 w-full max-w-4xl h-[80vh] rounded-xl flex flex-col shadow-2xl border border-slate-700">
            <div className="flex justify-between items-center p-4 border-b border-slate-700">
               <h3 className="text-white font-bold flex items-center gap-2">
                 <FileJson className="w-5 h-5 text-yellow-400" />
                 Resume Data Editor (JSON)
               </h3>
               <button onClick={handleExportJson} className="text-xs text-blue-400 hover:underline">Download JSON Backup</button>
            </div>
            <div className="flex-1 p-0 relative">
               <textarea 
                  value={jsonInput}
                  onChange={(e) => setJsonInput(e.target.value)}
                  className="w-full h-full bg-slate-900 text-slate-300 font-mono text-sm p-4 resize-none focus:outline-none"
                  spellCheck={false}
               />
               {jsonError && (
                 <div className="absolute bottom-4 left-4 right-4 bg-red-900/90 text-red-200 px-4 py-2 rounded border border-red-700 text-sm">
                   {jsonError}
                 </div>
               )}
            </div>
            <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-800 rounded-b-xl">
               <button 
                 onClick={() => setIsEditing(false)}
                 className="px-4 py-2 text-slate-300 hover:text-white hover:bg-slate-700 rounded-md transition-colors"
               >
                 Cancel
               </button>
               <button 
                 onClick={handleSaveJson}
                 className="px-6 py-2 bg-green-600 hover:bg-green-500 text-white font-semibold rounded-md flex items-center gap-2 shadow-lg hover:shadow-green-500/20 transition-all"
               >
                 <Save className="w-4 h-4" />
                 Save Changes
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Container */}
      <main className="flex justify-center px-4 md:px-8 print:px-0 print:block">
        <div className="w-full max-w-[210mm] print:max-w-none">
          <div className="mb-4 text-center print:hidden">
            <p className="text-slate-400 text-sm">
              <strong className="text-green-400">New:</strong> Click "Edit Data" to customize your resume. Changes save automatically.
            </p>
          </div>

          {/* Resume Component with Dynamic Data */}
          <ResumePaper data={resumeData} />

          <footer className="mt-12 text-center text-slate-500 text-xs print:hidden">
             <p>&copy; {new Date().getFullYear()} Alex Diakov. Optimized for Print & ATS.</p>
          </footer>
        </div>
      </main>
    </div>
  );
};

