          {data.contact.map((item) => (
            <a key={item.label} href={item.link} className="text-resume-accent hover:text-resume-accent/80 transition-colors">
              {ICONS[item.label as keyof typeof ICONS]}
            </a>
          ))}
        </div>
      </div>

      <SectionHeader title="Experience" />
      {data.experience.map((item: ExperienceItem) => (
        <div key={item.company} className="mb-6">
          <div className="flex justify-between items-center mb-1">
            <span className="font-semibold text-resume-accent">{item.company}</span>
            <span className="text-resume-secondary text-sm">{item.date}</span>
          </div>
          <h4 className="text-lg font-semibold">{item.title}</h4>
